declare @invoke nvarchar(4000)
select @invoke = ''
&ListDeleted;
&PostDeleted;
select @invoke as invoke






        /* <flatten type="Javascript"> */
var f = this, v = f._language == 'v', name = 'd11', extension = 'r30', g = f.getItem(name)._controlBehavior, z = f.getItem(extension)._controlBehavior, d = 5;
var a = query$Select(g, 'sum$ps_no_nt, sum$ps_co_nt, sum$ps_no, sum$ps_co, sum$([ps_no] == 0 ? 0 : 1), sum$([ps_co] == 0 ? 0 : 1) $groupBy nh_dk');
var l0, l1 = g._getColumnOrder('so_ct0'), l2 = g._getColumnOrder('ngay_ct0');

var e1 = (v ? 'Chưa nhập đủ tài khoản nợ hoặc có trong nhóm định khoản <span class="Highlight">%s</span>.' : 'You have not entered all debit or credit entries in the records (group = <span class="Highlight">%s</span>).');
var e2 = (v ? 'Có hạch toán nhiều nợ, nhiều có trong nhóm định khoản <span class="Highlight">%s</span>.' : 'There are multi debit credit entries in the records (group = <span class="Highlight">%s</span>).');
var e3 = (v ? 'Phát sinh nợ và phát sinh có khác nhau trong nhóm định khoản <span class="Highlight">%s</span>.' : 'Difference between total debit and total credit (group = <span class="Highlight">%s</span>).');
var e4 = (v ? 'Thông tin thuế trên bảng kê khác với thông tin thuế ghi sổ trong chi tiết của tài khoản <span class="Highlight">%s</span>.' : 'Tax data in VAT invoice listing is different from one in tax account ledger (account = <span class="Highlight">%s</span>).');

for (var i = 0; i < a.length; i++) {
  var c = a[i][0], n1 = a[i][5], n2 = a[i][6];
  if (n1 * n2 == 0) {on$Voucher$Error(f, e1, c, name); break;}
  if ((n1 - 1) * (n2 - 1) != 0) {on$Voucher$Error(f, e2, c, name); break;}
  if ((a[i][1].toFixed(d) != a[i][2].toFixed(d)) || (a[i][3].toFixed(d) != a[i][4].toFixed(d))) {on$Voucher$Error(f, e3, c, name); break;}
}

if (f._checked && f._taxVerify) {
  a = query$Select(z, 'sum$t_thue_nt, sum$t_thue $groupBy tk_thue_no');
  for (var i = 0; i < a.length; i++) {
    var c = $func.trim(a[i][0]), c1 = 'ps_no_nt', c2 = 'ps_no', t1 = a[i][1], t2 = a[i][2], expression = '$func.trim([tk])==\'' + c + '\'';
    if (t1 < 0) {
      t1 = Math.abs(t1), t2 = Math.abs(t2);
      c1 = 'ps_co_nt', c2 = 'ps_co';
    }
    var n1 = g.sum(c1, expression), n2 = g.sum(c2, expression);
    if ((t1.toFixed(d) != n1.toFixed(d)) || (t2.toFixed(d) != n2.toFixed(d))) {on$Voucher$Error(f, e4, c, extension); break;}
  }
}
if (f._udfPaymentControl && f._checked) {
  for (var i = 1; i <= g._rowCount; i++) {
    if (!$func.trim(g._getItemValue(i, l1)) && g._getItemValue(i, l2)) {
      l0 = l1;
      g._errorPaymentObject = g._getItem(i, l0);
      f._checked = false;
      break;
    }
    if ($func.trim(g._getItemValue(i, l1)) && !g._getItemValue(i, l2)) {
      l0 = l2;
      g._errorPaymentObject = g._getItem(i, l0);
      f._checked = false;
      break;
    }
  }
  if (!f._checked) {
    var message = String.format($df.getResources(f._language, 'Message.RequiredField'), g._fields[l0 - 1].HeaderText);
    $message.show(message, String.format('$find(\'{0}\').focus(\'{1}\');$find(\'{2}\')._errorPaymentObject.focus()', f._id, name, g._id));
  }
}
/* </flatten> */
