script.text:
      &ScriptQueryData;
      &ScriptVoucherInit;
      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, null, null, null, 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
  &ListCreate;
  &PostCreate;
  &VoucherLogHandleStatus;
}
function scatter$Voucher$(f) {&ScriptScatterVoucher;&VoucherLogHandleStatus;}
function close$Voucher$(f) {&ScriptCloseVoucher;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  &ListDispose;
  &PostDispose;
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d11')._controlBehavior, z = f.getItem('r30')._controlBehavior;
  switch (action) {
    case 'Check':
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      z.setSequenceNumber('line_nbr');
      z.setContinuance('stt_rec0');
      break;
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Explore':
      &VoucherLogHandleStatusExplore;
      break;
    default:
      break;
  }
}

      &ScriptVoucherNumber;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d11')._controlBehavior, z = f.getItem('r30')._controlBehavior;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.Currency, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency, flush: true}, null, null, c);
    v.set_currencyFields('t_ps_no_nt,t_ps_co_nt:t_ps_no,t_ps_co');
    v.addGridFields(z, 't_tien_nt,t_thue_nt:t_tien,t_thue');
    v.addGridFields(g, 'ps_no_nt, ps_co_nt:ps_no, ps_co');
    v.addTotalFields(g, [['t_ps_no_nt', 'ps_no_nt'], ['t_ps_no', 'ps_no'], ['t_ps_co_nt', 'ps_co_nt'], ['t_ps_co', 'ps_co']]);

    v.set_referenceFields(null);
&CurrencyDateChanged;
  onCurrencySelected: function(sender, e) {if (e.object._baseCurrency == e.type) e.object._form.getItem('dien_giai').focus();}
}



function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d11', 'r30'&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Memo(o) {
  var g = o.parentForm.getItem("d11")._controlBehavior;
  if ((o.parentForm._action == 'New') && (g._rowCount > 0) && (g._getItemValue(1, g._getColumnOrder('dien_giai')) == ''))
    g._getItem(1, g._getColumnOrder('dien_giai')).value = o.value;
}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &ListScattering;
      &PostScattering;
      break;

      &VoucherNumberReading;
      &CurrencyResponse;

    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      break;
    &ListResponseTicket;
    default:
        break;
  }
}
/* <flatten type="Javascript"> */
function on$Voucher$Error(f, errorMessage, s, c) {
  f._checked = false;
  $func.hideWait(f.get_id());
  $message.show(errorMessage.replace("%s", s), String.format('$find(\'{0}\').focus(\'{1}\');', f.get_id(), c));
}
/* </flatten> */
      &ScriptVerifyInputVATInvoiceNumber;
      &ListScript;
      &PostScript;
